  `,document.body.appendChild(n),window.__hideSearch=d;const a=n.querySelector(".search-panel__input");if(document.addEventListener("keydown",e=>{if((e.key==="k"||e.key==="/")&&!e.ctrlKey&&!e.metaKey){const r=e.target;if(r.tagName==="INPUT"||r.tagName==="TEXTAREA")return;e.preventDefault(),v()}e.key==="Escape"&&d()}),a){let e;a.addEventListener("input",()=>{clearTimeout(e),e=setTimeout(()=>{const r=u(a.value);y(r),n.classList.remove("hidden")},200)})}}function v(){if(!n)return;n.classList.remove("hidden");const a=n.querySelector(".search-panel__input");a&&(a.value="",a.focus())}function d(){if(!n)return;n.classList.add("hidden");const a=n.querySelector(".search-panel__input");a&&(a.value="")}function y(a){if(!n)return;const e=n.querySelector(".search-panel__results");if(e){if(a.length===0){e.innerHTML='<div class="search-panel__empty">未找到相关结果</div>';return}e.innerHTML=a.map(r=>{const s=r.type==="story"?"故事":r.type==="character"?"人物":"地标",t=r.type==="story"?"search-result__type--story":r.type==="character"?"search-result__type--char":"search-result__type--place";return`
